mapper.insert:
insert into exam_paper(
  id, course_id, title, duration_minutes, start_at, end_at, shuffle_questions, creator_id, status, created_at
) values (
  #{id}, #{courseId}, #{title}, #{durationMinutes}, #{startAt}, #{endAt}, #{shuffleQuestions}, #{creatorId}, 0, now()
)

mapper.select:
select p.*
from exam_paper p
join course c on c.id = p.course_id
where p.id = #{paperId}
  and p.course_id = #{courseId}
  and c.teacher_id = #{teacherId}
  and c.status = 1
limit 1

mapper.update:
update exam_paper p
join course c on c.id = p.course_id
set p.status = 1
where p.id = #{paperId}
  and p.course_id = #{courseId}
  and c.teacher_id = #{teacherId}
  and c.status = 1
  and p.status = 0

mapper.insert:
insert into exam_question(
  id, paper_id, q_type, stem, score, sort_no, correct_answer, status
) values (
  #{id}, #{paperId}, #{qType}, #{stem}, #{score}, #{sortNo}, #{correctAnswer}, 1
)

insert into exam_option(
  id, question_id, opt_key, opt_text, sort_no, status
) values (
  #{id}, #{questionId}, #{optKey}, #{optText}, #{sortNo}, 1
)

insert into exam_attempt(
  id, paper_id, student_id, started_at, status
) values (
  #{id}, #{paperId}, #{studentId}, now(), 1
)

mapper.select:
select *
from exam_attempt
where id = #{attemptId}
  and student_id = #{studentId}
limit 1

select a.*
from exam_attempt a
join exam_paper p on p.id = a.paper_id
join course c on c.id = p.course_id
where a.id = #{attemptId}
  and a.paper_id = #{paperId}
  and p.course_id = #{courseId}
  and c.teacher_id = #{teacherId}
  and c.status = 1
limit 1

select ea.answer
from exam_answer ea
where ea.attempt_id = #{attemptId}
  and ea.question_id = #{questionId}
limit 1

mapper.update:
update exam_answer ea
inner join exam_attempt att on att.id = ea.attempt_id
inner join exam_paper p on p.id = att.paper_id
inner join course c on c.id = p.course_id
set ea.score = #{score}
where ea.attempt_id = #{attemptId}
  and ea.question_id = #{questionId}
  and att.paper_id = #{paperId}
  and p.course_id = #{courseId}
  and c.teacher_id = #{teacherId}
  and att.status = 2

mapper.select:
select coalesce(sum(ea.score), 0)
from exam_answer ea
where ea.attempt_id = #{attemptId}

mapper.update:
update exam_attempt att
inner join exam_paper p on p.id = att.paper_id
inner join course c on c.id = p.course_id
set att.total_score = #{totalScore},
    att.objective_score = #{objectiveScore}
where att.id = #{attemptId}
  and att.paper_id = #{paperId}
  and p.course_id = #{courseId}
  and c.teacher_id = #{teacherId}
  and att.status = 2

mapper.select:
select avg(t.best_score)
from (
  select a.paper_id, max(a.total_score) as best_score
  from exam_attempt a
  join exam_paper p on p.id = a.paper_id
  where p.course_id = #{courseId}
    and p.status = 1
    and a.student_id = #{studentId}
    and a.status = 2
  group by a.paper_id
) t

select max(a.total_score)
from exam_attempt a
where a.paper_id = #{paperId}
  and a.student_id = #{studentId}
  and a.status = 2
